308→export const saveProgressService = async (storyId, userId, chapterId, scrollPosition) => {
309→    if (!storyId || !userId || !chapterId) {
310→        throw { status: 400, error: 'storyId, userId, and chapterId are required' };
311→    }
312→
313→    // Check if this is a new reader (no existing progress for this user+story)
314→    const { data: existing } = await supabase
315→        .from('reading_progress')
316→        .select('id')
317→        .eq('user_id', userId)
318→        .eq('story_id', storyId)
319→        .maybeSingle();
320→
321→    const { data, error } = await supabase
322→        .from('reading_progress')
323→        .upsert({
324→            user_id: userId,
325→            story_id: storyId,
326→            chapter_id: chapterId,
327→            scroll_position: scrollPosition || 0,
328→            last_read_at: new Date().toISOString(),
329→        }, { onConflict: 'user_id,story_id' })
330→        .select('*')
331→        .single();
332→
333→    if (error) {
334→        console.error('supabase error saving progress:', error.message);
335→        throw { status: 500, error: 'failed to save progress' };
336→    }
337→
338→    // Increment read_count if this is a new reader (skip if author)
339→    if (!existing) {
340→        const { data: story } = await supabase
341→            .from('stories')
342→            .select('author_id')
343→            .eq('id', storyId)
344→            .single();
345→
346→        if (story && story.author_id !== userId) {
347→            const { error: rpcError } = await supabase.rpc('increment_story_reads', { story_id_input: storyId });
348→            if (rpcError) {
349→                console.error('error incrementing story reads:', rpcError.message);
350→            }
351→        }
352→    }
353→
354→    return data;
355→};
